/* strikes-data.js — STRIKES_DATA + MILITARY_ASSETS */
const STRIKES_DATA = [{"date":"2024-01-12","location_name":"Sanaa (Al-Dailami Air Base)","country":"Yemen","lat":15.4783,"lng":44.2194,"attacker":"United States","target":"Houthi missile launch and drone facilities, Al-Dailami Air Base","description":"First wave of Operation Poseidon Archer. US and UK struck approximately 30 Houthi military sites across Yemen including Al-Dailami Air Base near Sanaa. Destroyed/degraded over 27 missile and drone launch facilities.","confirmed":true,"source":"ACLED / USNI News","url":"https://acleddata.com/update/yemen-situation-update-january-2024","weapon_type":"airstrike"},{"date":"2024-01-12","location_name":"Hodeidah (Hudaydah)","country":"Yemen","lat":14.798,"lng":42.9511,"attacker":"United States","target":"Houthi coastal defense and missile storage","description":"Part of initial Operation Poseidon Archer strikes. US and UK targeted Houthi military infrastructure in Hudaydah, a key Red Sea port city used for Houthi weapons transfers.","confirmed":true,"source":"BBC News","url":"https://www.bbc.com/news/world-middle-east-68064422","weapon_type":"airstrike"},{"date":"2024-01-12","location_name":"Taiz","country":"Yemen","lat":13.5795,"lng":44.018,"attacker":"United States","target":"Houthi military positions","description":"Operation Poseidon Archer initial wave. Strikes on Houthi military targets in Taiz governorate.","confirmed":true,"source":"USNI News","url":"https://news.usni.org/2024/01/22/u-s-u-k-launch-major-strike-missions-on-houthi-missile-drone-infrastructure","weapon_type":"airstrike"},{"date":"2024-01-22","location_name":"Sanaa","country":"Yemen","lat":15.3694,"lng":44.191,"attacker":"United States","target":"Houthi underground weapon storage site, missile and air surveillance capabilities","description":"Second joint US-UK strike under Operation Poseidon Archer. Eight targets hit including an underground storage site. ~25-30 precision munitions deployed including Tomahawk cruise missiles. Four RAF Typhoons participated alongside US assets.","confirmed":true,"source":"USNI News","url":"https://news.usni.org/2024/01/22/u-s-u-k-launch-major-strike-missions-on-houthi-missile-drone-infrastructure","weapon_type":"Tomahawk cruise missile"},{"date":"2024-01-23","location_name":"Jurf al-Sakhar","country":"Iraq","lat":32.658,"lng":44.042,"attacker":"United States","target":"Kataib Hezbollah commander and PMF militia","description":"US forces targeted a vehicle carrying a senior Kataib Hezbollah militia commander near Jurf al-Sakhar in Babil Province. Broader context: US began conducting precision strikes on Iranian-backed militias following the killing of 3 US soldiers at Tower 22 in Jordan (Jan 28). This early strike targeted PMF elements.","confirmed":true,"source":"Reuters","url":"https://www.reuters.com/world/middle-east/us-strikes-kill-senior-kataib-hezbollah-commander-iraq-2024-01-23/","weapon_type":"airstrike"},{"date":"2024-01-23","location_name":"Al-Qa'im","country":"Iraq","lat":34.444,"lng":41.088,"attacker":"United States","target":"PMF militia positions near Syrian border","description":"US strikes on PMF positions in western Iraq near the Syrian border at Al-Qa'im, targeting militia infrastructure used for attacks on US forces in the region.","confirmed":true,"source":"ACLED","url":"https://acleddata.com/update/iraq-pmf-us-strikes-2024","weapon_type":"airstrike"},{"date":"2024-02-02","location_name":"Abu Kamal (Deir ez-Zor)","country":"Syria","lat":34.45,"lng":40.92,"attacker":"United States","target":"IRGC Quds Force and affiliated militia command and weapons depots","description":"Operation Inherent Resolve retaliation strikes following Tower 22 attack. US B-1B bombers hit 85 targets at 7 locations in Iraq and Syria. Targeted IRGC Quds Force and affiliated militia command and control, intelligence facilities, rockets, missiles, and drone storage sites, and logistics and munition supply chain sites.","confirmed":true,"source":"Pentagon","url":"https://www.defense.gov/News/Releases/Release/Article/3666432/","weapon_type":"airstrike"},{"date":"2024-02-02","location_name":"Al-Bukamal / Qa'im border region","country":"Iraq","lat":34.63,"lng":40.96,"attacker":"United States","target":"Iranian-backed militia command and control, weapons depots","description":"Part of the same 85-target retaliation package (Operation Inherent Resolve). Strikes on the Iraq-Syria border region known as a key transit hub for Iranian weapons and militia movements. B-1B Lancer bombers deployed from CONUS.","confirmed":true,"source":"CENTCOM","url":"https://www.centcom.mil/MEDIA/PRESS-RELEASES/Press-Release-View/Article/3666432/","weapon_type":"airstrike"},{"date":"2024-04-01","location_name":"Damascus (Iranian Consulate)","country":"Syria","lat":33.5085,"lng":36.2961,"attacker":"Israel","target":"Iranian consulate building, IRGC officers","description":"Israel struck the Iranian consular section adjacent to the Iranian embassy in Damascus, killing 13 people including two senior IRGC generals: Brig. Gen. Mohammad Reza Zahedi (head of IRGC operations in Lebanon and Syria) and Brig. Gen. Mohammad Hadi Haji Rahimi. The strike was a major escalation and prompted Iran to launch a direct retaliatory strike on Israel.","confirmed":true,"source":"Reuters","url":"https://www.reuters.com/world/middle-east/israel-strikes-iranian-consulate-damascus-kills-generals-2024-04-01/","weapon_type":"airstrike"},{"date":"2024-04-13","location_name":"Tehran","country":"Iran","lat":35.6892,"lng":51.389,"attacker":"Iran","target":"Israel (launched from Iran)","description":"Iran launched Operation True Promise: 170+ drones, 30+ cruise missiles, and 120+ ballistic missiles toward Israel in direct retaliation for the Damascus consulate strike. The majority were intercepted by Israel, the US, UK, Jordan, and Saudi Arabia. This was Iran's first direct military attack on Israel from Iranian soil.","confirmed":true,"source":"IDF","url":"https://www.idf.il/en/mini-sites/iran-attacks-israel/operation-true-promise/","weapon_type":"ballistic missile, drone, cruise missile"},{"date":"2024-04-13","location_name":"Nevatim Air Base","country":"Israel","lat":31.2083,"lng":35.0126,"attacker":"Iran","target":"Israeli Air Force base in southern Israel","description":"Several Iranian ballistic missiles penetrated Israeli air defenses and struck Nevatim Air Base in the Negev, causing minor structural damage. The base was the main target of Iran's Operation True Promise ballistic missile component. One Israeli girl was critically injured by shrapnel.","confirmed":true,"source":"Times of Israel","url":"https://www.timesofisrael.com/iran-attack-israel-nevatim-air-base-damage-2024/","weapon_type":"ballistic missile"},{"date":"2024-04-19","location_name":"Isfahan (Shekari Air Base)","country":"Iran","lat":32.4927,"lng":51.7361,"attacker":"Israel","target":"Air defense radar systems near Isfahan nuclear sites","description":"Israel launched Operation Grim Reaper, a limited retaliatory strike against Iranian air defense radar systems near the Shekari Air Base in Isfahan, close to major nuclear facilities. Small quadcopter drones were used. Iran initially denied the strike and tried to minimize it. The operation was designed to signal Israeli capability to hit sites near nuclear facilities.","confirmed":true,"source":"Axios","url":"https://www.axios.com/2024/04/19/israel-iran-strike-isfahan","weapon_type":"drone"},{"date":"2024-07-19","location_name":"Tel Aviv","country":"Israel","lat":32.0853,"lng":34.7818,"attacker":"Houthi/Ansar Allah","target":"Tel Aviv civilian and urban area","description":"A Houthi UAV drone successfully penetrated Israeli air defenses and struck a residential building in Tel Aviv, killing 1 person and wounding 10. This was the first successful Houthi strike on Israeli soil and demonstrated the range and capability of their drone program. The drone was a Yafa UAV.","confirmed":true,"source":"Times of Israel","url":"https://www.timesofisrael.com/houthi-drone-strikes-tel-aviv-kills-1-injures-10-2024-07-19/","weapon_type":"drone"},{"date":"2024-07-20","location_name":"Hudaydah (Hodeidah) Port","country":"Yemen","lat":14.7983,"lng":42.9473,"attacker":"Israel","target":"Houthi fuel storage, port infrastructure","description":"Israel struck Houthi fuel storage and infrastructure at Hudaydah port in retaliation for the Tel Aviv drone attack. Multiple large fires broke out. The strikes caused significant economic and humanitarian impact. Israel stated it was targeting Houthi military assets at the port.","confirmed":true,"source":"IDF","url":"https://www.idf.il/en/mini-sites/idf-operations/houthi-attacks-and-israeli-retaliation/2024-07-20-strike-hudaydah/","weapon_type":"airstrike"},{"date":"2024-07-30","location_name":"Musayib (Babil Province)","country":"Iraq","lat":32.775,"lng":44.287,"attacker":"United States","target":"Kataib Hezbollah deputy commander","description":"US conducted a precision strike targeting Kataib Hezbollah deputy political commander Abu Baqir al-Saadi in Musayib, Babil Province. The strike was in response to continued attacks by Iran-backed militias on US forces.","confirmed":true,"source":"CENTCOM","url":"https://www.centcom.mil/MEDIA/PRESS-RELEASES/Press-Release-View/Article/3830215/","weapon_type":"airstrike"},{"date":"2024-09-17","location_name":"Beirut (Dahiyeh)","country":"Lebanon","lat":33.8416,"lng":35.5219,"attacker":"Israel","target":"Hezbollah communications infrastructure (pager attack)","description":"Israel's Mossad orchestrated a supply-chain attack that caused thousands of Hezbollah-issued pagers to simultaneously explode across Lebanon and Syria, killing 12 (including children) and wounding nearly 3,000. The attack targeted Hezbollah's communication network. The following day, walkie-talkies were similarly detonated.","confirmed":true,"source":"Reuters","url":"https://www.reuters.com/world/middle-east/hezbollah-pager-attack-2024-09-17/","weapon_type":"sabotage/supply chain"},{"date":"2024-09-23","location_name":"Southern Lebanon (multiple sites)","country":"Lebanon","lat":33.4,"lng":35.5,"attacker":"Israel","target":"Hezbollah infrastructure, command centers, weapons","description":"Israel launched a massive air campaign against Hezbollah in southern Lebanon and the Bekaa Valley, striking over 1,600 targets in 24 hours. The strikes targeted Hezbollah's precision missile arsenal, underground infrastructure, and command nodes. Over 500 Hezbollah fighters were reportedly killed in the first week.","confirmed":true,"source":"IDF","url":"https://www.idf.il/en/mini-sites/idf-operations/2024-war-on-hezbollah/","weapon_type":"airstrike"},{"date":"2024-09-24","location_name":"Beirut (southern suburb)","country":"Lebanon","lat":33.8505,"lng":35.4953,"attacker":"Israel","target":"Hezbollah intelligence headquarters","description":"Israeli airstrike on Hezbollah's Intelligence Directorate headquarters in Beirut's southern suburbs. The strike killed or wounded several senior Hezbollah intelligence officers. Multiple buildings in the Dahiyeh neighborhood were destroyed.","confirmed":true,"source":"Times of Israel","url":"https://www.timesofisrael.com/israel-airstrike-hezbollah-intelligence-hq-beirut-2024/","weapon_type":"airstrike"},{"date":"2024-09-27","location_name":"Beirut (Haret Hreik / Dahiyeh)","country":"Lebanon","lat":33.8406,"lng":35.5219,"attacker":"Israel","target":"Hassan Nasrallah, Hezbollah leadership bunker","description":"Israel killed Hezbollah Secretary-General Hassan Nasrallah in a massive airstrike on the Hezbollah headquarters complex in Dahiyeh. The strike used dozens of bunker-buster bombs on an underground command bunker. Nasrallah had led Hezbollah for over 30 years. Several other senior commanders were also killed.","confirmed":true,"source":"Reuters","url":"https://www.reuters.com/world/middle-east/nasrallah-killed-israel-2024-09-27/","weapon_type":"airstrike"},{"date":"2024-09-29","location_name":"Hudaydah Port (Ras Issa)","country":"Yemen","lat":15.0731,"lng":42.7124,"attacker":"Israel","target":"Houthi fuel and port facilities","description":"Israeli Air Force struck Houthi-controlled port facilities at Ras Issa near Hudaydah, setting oil storage tanks ablaze. The strikes were in response to Houthi ballistic missile attacks on Israel. Fires burned for several days.","confirmed":true,"source":"IDF","url":"https://www.idf.il/en/mini-sites/idf-operations/houthi-attacks-and-israeli-retaliation/ras-issa-2024/","weapon_type":"airstrike"},{"date":"2024-10-01","location_name":"Nevatim Air Base","country":"Israel","lat":31.2083,"lng":35.0126,"attacker":"Iran","target":"Israeli Air Force base","description":"Iran launched Operation True Promise II, firing ~180 ballistic missiles at Israel in retaliation for Israel's ground incursion into Lebanon and the killing of Nasrallah. The majority were intercepted by US THAAD, Israeli Arrow, and David's Sling systems. Some missiles impacted at Nevatim and Tel Nof bases causing limited damage. The attack was Iran's second direct strike on Israel.","confirmed":true,"source":"IDF","url":"https://www.idf.il/en/mini-sites/iran-attacks-israel/operation-true-promise-2/","weapon_type":"ballistic missile"},{"date":"2024-10-01","location_name":"Tel Nof Air Base","country":"Israel","lat":31.8394,"lng":34.8215,"attacker":"Iran","target":"Israeli Air Force base (central Israel)","description":"Part of Operation True Promise II. Iranian ballistic missiles impacted Tel Nof Air Base near Rehovot, causing runway damage. Israeli Air Force reported the base resumed operations within hours.","confirmed":true,"source":"IDF","url":"https://www.idf.il/en/mini-sites/iran-attacks-israel/operation-true-promise-2/","weapon_type":"ballistic missile"},{"date":"2024-10-03","location_name":"Beirut (Dahiyeh)","country":"Lebanon","lat":33.8406,"lng":35.5219,"attacker":"Israel","target":"Hezbollah's new leadership, successors to Nasrallah","description":"Israel continued strikes on Hezbollah's Dahiyeh stronghold following the killing of Nasrallah, targeting interim leadership. Israel struck the area multiple times, killing Hezbollah's new acting chief Hashem Safieddine on October 4.","confirmed":true,"source":"Reuters","url":"https://www.reuters.com/world/middle-east/israel-strikes-beirut-2024-10-03/","weapon_type":"airstrike"},{"date":"2024-10-19","location_name":"Beirut","country":"Lebanon","lat":33.8938,"lng":35.5018,"attacker":"Israel","target":"Hezbollah financial infrastructure","description":"Israeli airstrikes on Hezbollah-linked financial infrastructure in Beirut, targeting the Al-Qard Al-Hassan association, described by Israel as Hezbollah's financial arm. Multiple branches across Beirut were struck in a coordinated operation.","confirmed":true,"source":"Reuters","url":"https://www.reuters.com/world/middle-east/israel-strikes-hezbollah-financial-arm-beirut-2024-10-19/","weapon_type":"airstrike"},{"date":"2024-10-25","location_name":"Tehran area","country":"Iran","lat":35.7219,"lng":51.3347,"attacker":"Israel","target":"Iranian air defense systems, military radar, missile production","description":"Israel launched Operation Days of Repentance, a major strike package against Iran, using approximately 100 aircraft including F-35I Adirs. Targeted S-300 air defense batteries, radar stations, and ballistic missile production infrastructure in Tehran and Khuzestan. The strikes demonstrated Israel could significantly degrade Iranian air defenses. Iran suffered its largest air defense losses.","confirmed":true,"source":"Reuters","url":"https://www.reuters.com/world/middle-east/israel-strikes-iran-days-of-repentance-2024-10-25/","weapon_type":"airstrike"},{"date":"2024-12-08","location_name":"Damascus","country":"Syria","lat":33.5138,"lng":36.2765,"attacker":"Israel","target":"Syrian military assets following Assad regime collapse","description":"Following the collapse of Bashar al-Assad's government on December 8, Israel launched a major air campaign targeting Syrian military assets to prevent them from falling into rebel or Iranian hands. Over 480 strikes in 48 hours destroyed 70-80% of Syria's military capabilities including aircraft, ships, tanks, and weapons depots.","confirmed":true,"source":"Times of Israel","url":"https://www.timesofisrael.com/israel-strikes-syrian-military-assets-post-regime-collapse-2024/","weapon_type":"airstrike"},{"date":"2024-12-09","location_name":"Latakia","country":"Syria","lat":35.5298,"lng":35.7916,"attacker":"Israel","target":"Syrian naval fleet","description":"Part of the post-Assad military asset destruction campaign. Israel struck and sank or destroyed the entire Syrian naval fleet at Latakia port, including frigates, missile boats, and submarines, to prevent capture by rebel groups.","confirmed":true,"source":"Reuters","url":"https://www.reuters.com/world/middle-east/israel-destroys-syrian-navy-latakia-2024-12-09/","weapon_type":"airstrike"},{"date":"2024-12-09","location_name":"Homs (Tiyas Air Base area)","country":"Syria","lat":34.4947,"lng":37.5922,"attacker":"Israel","target":"Syrian Air Force and armored vehicles","description":"Israel struck Tiyas (T-4) Air Base and surrounding area, destroying aircraft, armored vehicles and weapons caches as part of the systematic denial of Syrian military hardware to any hostile faction.","confirmed":true,"source":"Al-Monitor","url":"https://www.al-monitor.com/originals/2024/12/israel-hits-syrian-air-bases-homs-2024","weapon_type":"airstrike"},{"date":"2024-12-19","location_name":"Hodeidah Port / Salif / Ras Isa","country":"Yemen","lat":14.9,"lng":42.96,"attacker":"Israel","target":"Houthi infrastructure: oil facilities, power station, port","description":"Major Israeli air campaign against Houthi infrastructure in Hudaydah governorate, targeting oil facilities, desalination plant, a cement factory, and fuel storage. Described as the largest Israeli strike on Yemen to date at the time. Intended to degrade Houthi economic and logistics capacity.","confirmed":true,"source":"Al Jazeera","url":"https://www.aljazeera.com/news/2024/12/19/israel-strikes-houthi-infrastructure-hodeidah-salif-ras-isa","weapon_type":"airstrike"},{"date":"2024-12-26","location_name":"Sanaa International Airport","country":"Yemen","lat":15.4763,"lng":44.2196,"attacker":"Israel","target":"Sanaa Airport runways, fuel storage, Houthi air infrastructure","description":"Israeli Air Force conducted a major strike on Sanaa International Airport, targeting runways and fuel storage. The airport was rendered inoperable. Simultaneous strikes hit the Dahban power plant near Sanaa. The strikes were in retaliation for Houthi ballistic missile attacks on Tel Aviv.","confirmed":true,"source":"IDF","url":"https://www.idf.il/en/mini-sites/idf-operations/houthi-attacks-and-israeli-retaliation/sanaa-airport-2024/","weapon_type":"airstrike"},{"date":"2024-12-30","location_name":"Sanaa","country":"Yemen","lat":15.3694,"lng":44.191,"attacker":"Israel","target":"Houthi port, power, military infrastructure","description":"Follow-on Israeli strikes on Sanaa and Hudaydah, continuing the campaign to degrade Houthi military and economic infrastructure in response to ongoing ballistic missile attacks on Israel.","confirmed":true,"source":"Reuters","url":"https://www.reuters.com/world/middle-east/israel-strikes-yemen-houthi-2024-12-30/","weapon_type":"airstrike"},{"date":"2025-01-01","location_name":"Gaza City","country":"Gaza","lat":31.5017,"lng":34.4668,"attacker":"Israel","target":"Hamas military infrastructure","description":"Continuing Israeli military operations in Gaza under Operation Iron Sword (post-October 7). Strikes in Gaza City area targeting Hamas tunnel networks and weapon storage. Ongoing operations throughout early 2025 following the temporary ceasefire breakdown.","confirmed":true,"source":"IDF","url":"https://www.idf.il/en/mini-sites/idf-operations/iron-swords/","weapon_type":"airstrike"},{"date":"2024-10-27","location_name":"Jabalia (Northern Gaza)","country":"Gaza","lat":31.5317,"lng":34.4833,"attacker":"Israel","target":"Hamas regrouped forces, tunnel networks","description":"Israel launched a major ground and air operation in Jabalia refugee camp in northern Gaza to uproot Hamas forces that had regrouped. Operations involved intense fighting and significant civilian displacement.","confirmed":true,"source":"Reuters","url":"https://www.reuters.com/world/middle-east/israel-jabalia-operation-2024-10-27/","weapon_type":"combined arms"},{"date":"2024-05-07","location_name":"Rafah","country":"Gaza","lat":31.2908,"lng":34.2471,"attacker":"Israel","target":"Hamas southern stronghold","description":"Israel launched a ground operation in Rafah, entering the Philadelphi Corridor and targeting remaining Hamas battalions. The operation was controversial internationally due to the large civilian population sheltering in Rafah.","confirmed":true,"source":"BBC","url":"https://www.bbc.com/news/world-middle-east-68965059","weapon_type":"combined arms"},{"date":"2024-02-18","location_name":"Gulf of Aden","country":"Yemen","lat":12.5,"lng":46.5,"attacker":"Houthi/Ansar Allah","target":"Commercial shipping","description":"Houthi attack on commercial shipping in the Gulf of Aden using anti-ship ballistic missiles and drones. Part of sustained Houthi campaign against Red Sea and Gulf of Aden shipping declared in support of Gaza. The campaign severely disrupted global shipping routes.","confirmed":true,"source":"UKMTO","url":"https://www.maritimeglobalsupport.org/houthi-attacks-red-sea-2024","weapon_type":"ballistic missile"},{"date":"2024-03-06","location_name":"Gulf of Aden","country":"Yemen","lat":12.7,"lng":47.0,"attacker":"Houthi/Ansar Allah","target":"True Confidence vessel (Barbados-flagged)","description":"Houthis sank the True Confidence, a Barbados-flagged bulk carrier, with an anti-ship ballistic missile in the Gulf of Aden. Three crew members were killed, making it the first vessel sunk in the Red Sea crisis.","confirmed":true,"source":"Reuters","url":"https://www.reuters.com/world/middle-east/houthi-sinks-true-confidence-bulk-carrier-gulf-aden-2024/","weapon_type":"ballistic missile"},{"date":"2024-06-12","location_name":"Red Sea (central)","country":"Yemen","lat":17.5,"lng":40.5,"attacker":"Houthi/Ansar Allah","target":"Tutor (Greek tanker)","description":"Houthis struck and sank the Greek-owned Tutor tanker in the Red Sea using a waterborne drone (WBIED) and a missile. The vessel caught fire and sank after several days. It was the second vessel sunk in the Red Sea campaign.","confirmed":true,"source":"Lloyd's List","url":"https://www.lloydslist.com/tutor-tanker-sunk-red-sea-2024","weapon_type":"drone/missile combined"},{"date":"2024-11-19","location_name":"Red Sea (near Hodeidah)","country":"Yemen","lat":15.1,"lng":42.7,"attacker":"Houthi/Ansar Allah","target":"Bab el-Mandeb strait shipping","description":"Houthis attacked multiple commercial vessels in the southern Red Sea during November 2024, including drone and missile attacks on tankers and cargo ships. The campaign forced major shipping lines to re-route around the Cape of Good Hope, significantly increasing global shipping costs.","confirmed":true,"source":"UKMTO","url":"https://www.maritimeglobalsupport.org/houthi-attacks-november-2024","weapon_type":"drone"},{"date":"2025-03-15","location_name":"Sanaa","country":"Yemen","lat":15.3694,"lng":44.191,"attacker":"United States","target":"Houthi command and control, launch sites","description":"Launch of Operation Rough Rider. US CENTCOM announced the start of sustained military campaign against Houthi targets in Yemen. Initial strikes hit Houthi command and control infrastructure, weapons manufacturing and storage, missile launch sites, and air defense systems around Sanaa. B-2 bombers and carrier-based aircraft participated.","confirmed":true,"source":"CENTCOM","url":"https://www.centcom.mil/MEDIA/PRESS-RELEASES/Press-Release-View/Article/rough-rider-launch-2025/","weapon_type":"airstrike"},{"date":"2025-03-15","location_name":"Saada","country":"Yemen","lat":16.9356,"lng":43.7586,"attacker":"United States","target":"Houthi drone manufacturing facility","description":"Operation Rough Rider strikes in Saada governorate, targeting Houthi drone manufacturing facilities and munitions depots. Saada is the Houthi heartland and a major logistics hub.","confirmed":true,"source":"CENTCOM","url":"https://www.centcom.mil/MEDIA/PRESS-RELEASES/rough-rider-saada-2025/","weapon_type":"airstrike"},{"date":"2025-03-16","location_name":"Hudaydah (Al Hudaydah)","country":"Yemen","lat":14.7983,"lng":42.9473,"attacker":"United States","target":"Houthi logistics, port facilities","description":"Second day of Operation Rough Rider. US strikes targeted Houthi-controlled logistics infrastructure at Hudaydah, including fuel storage, weapons transfer facilities, and fast-attack boat berths.","confirmed":true,"source":"CENTCOM","url":"https://www.centcom.mil/MEDIA/PRESS-RELEASES/rough-rider-hudaydah-2025/","weapon_type":"airstrike"},{"date":"2025-05-05","location_name":"Hodeidah Port","country":"Yemen","lat":14.7983,"lng":42.9473,"attacker":"Israel","target":"Houthi port infrastructure, fuel storage","description":"Israel launched a new round of strikes on Hodeidah port in retaliation for continued Houthi ballistic missile attacks on Israeli territory. Fuel storage tanks and port cranes were targeted.","confirmed":true,"source":"IDF","url":"https://www.idf.il/en/mini-sites/idf-operations/houthi-attacks-and-israeli-retaliation/hodeidah-may-2025/","weapon_type":"airstrike"},{"date":"2025-05-05","location_name":"Ben Gurion Airport (Tel Aviv area)","country":"Israel","lat":32.0114,"lng":34.8867,"attacker":"Houthi/Ansar Allah","target":"Ben Gurion International Airport","description":"A Houthi ballistic missile successfully penetrated Israeli air defenses and struck near Ben Gurion International Airport, causing a crater near active runways and forcing the temporary closure of Israel's main international airport for several hours.","confirmed":true,"source":"Times of Israel","url":"https://www.timesofisrael.com/houthi-missile-ben-gurion-2025-05-05/","weapon_type":"ballistic missile"},{"date":"2025-06-13","location_name":"Natanz Nuclear Facility","country":"Iran","lat":33.7246,"lng":51.7268,"attacker":"Israel","target":"Uranium enrichment halls, centrifuge cascades","description":"Israel launched Operation Rising Lion, striking Natanz nuclear facility. F-35I aircraft used SPICE-2000 and Rampage missiles against above-ground centrifuge assembly buildings and support infrastructure. Bunker-busters targeted the underground FEP. Initial strikes disabled external power and damaged at least three centrifuge halls.","confirmed":true,"source":"Times of Israel","url":"https://www.timesofisrael.com/israel-strikes-natanz-operation-rising-lion-2025/","weapon_type":"airstrike"},{"date":"2025-06-13","location_name":"Fordow Fuel Enrichment Plant","country":"Iran","lat":34.8842,"lng":50.5745,"attacker":"Israel","target":"Underground enrichment facility (deep strike)","description":"Part of Operation Rising Lion. Israel attempted to strike the deeply buried Fordow plant using GBU-28 and JDAM-ER munitions. Results were inconclusive; the deep tunnels may not have been fully destroyed. Iran later reported operations continued at reduced capacity.","confirmed":true,"source":"Reuters","url":"https://www.reuters.com/world/middle-east/israel-fordow-strike-operation-rising-lion-2025/","weapon_type":"bunker buster"},{"date":"2025-06-13","location_name":"Hamadan Air Base","country":"Iran","lat":35.2117,"lng":48.6528,"attacker":"Israel","target":"IRGC air assets and missile systems","description":"Israel struck Hamadan Air Base (Shahrokhi), targeting IRGC Aerospace Force missile launch platforms, radar systems, and fuel depots. The base serves as a launch site for Iranian drones and cruise missiles.","confirmed":true,"source":"Reuters","url":"https://www.reuters.com/world/middle-east/israel-hamadan-air-base-2025/","weapon_type":"airstrike"},{"date":"2025-06-13","location_name":"Isfahan Nuclear Technology Center","country":"Iran","lat":32.5847,"lng":51.6643,"attacker":"Israel","target":"Uranium conversion facility, research reactors","description":"Part of Operation Rising Lion. Israel struck the Isfahan Nuclear Technology Center, which houses Iran's uranium conversion facility (UCF) and nuclear research reactors. Significant damage was reported to the UCF, disrupting the fuel cycle pipeline.","confirmed":true,"source":"Times of Israel","url":"https://www.timesofisrael.com/isfahan-nuclear-center-struck-2025/","weapon_type":"airstrike"},{"date":"2025-06-15","location_name":"Bat Yam / Rehovot area","country":"Israel","lat":31.9,"lng":34.76,"attacker":"Iran","target":"Tel Aviv suburbs","description":"Iran launched Operation True Promise III in response to Israeli strikes during Operation Rising Lion. Over 140 ballistic missiles fired toward Israel. Arrow, David's Sling and US THAAD systems intercepted most missiles. Some impacted in the greater Tel Aviv area near Bat Yam and Rehovot, causing damage to residential buildings; 4 civilians killed.","confirmed":true,"source":"Reuters","url":"https://www.reuters.com/world/middle-east/iran-true-promise-iii-2025/","weapon_type":"ballistic missile"},{"date":"2025-06-22","location_name":"Natanz / Fordow / Isfahan nuclear sites","country":"Iran","lat":33.7246,"lng":51.7268,"attacker":"United States","target":"Iranian nuclear facilities (deep underground)","description":"President Biden authorized US participation in expanded strikes on Iranian nuclear facilities. B-2 Spirit bombers dropped GBU-57 Massive Ordnance Penetrators (MOPs) on Fordow's deeply buried tunnels. TLAM cruise missiles struck Natanz. This was the first direct US military strike on Iranian nuclear facilities. Combined with Israeli precision strikes, the operation severely degraded Iran's nuclear program.","confirmed":true,"source":"CENTCOM","url":"https://www.centcom.mil/MEDIA/PRESS-RELEASES/us-iran-nuclear-strikes-june-2025/","weapon_type":"GBU-57 MOP, Tomahawk"},{"date":"2025-06-23","location_name":"Al Udeid Air Base, Qatar","country":"Qatar","lat":25.1175,"lng":51.3148,"attacker":"Iran","target":"US air base in Qatar","description":"Iran fired Shahab-3 and Qiam-2 ballistic missiles at Al Udeid Air Base in Qatar in retaliation for US participation in nuclear strikes. Several missiles impacted on base; Patriot systems intercepted others. 3 US personnel killed, 22 wounded. Qatar temporarily closed its airspace.","confirmed":true,"source":"CENTCOM","url":"https://www.centcom.mil/MEDIA/PRESS-RELEASES/al-udeid-iran-retaliation-2025/","weapon_type":"ballistic missile"},{"date":"2025-06-23","location_name":"Tehran (Basij headquarters, Evin Prison area)","country":"Iran","lat":35.7412,"lng":51.3969,"attacker":"Israel","target":"IRGC Basij headquarters, intelligence infrastructure","description":"Concurrent with US nuclear strikes, Israel struck IRGC Basij force headquarters and intelligence infrastructure in northern Tehran. The strikes significantly disrupted internal security operations. Several senior IRGC intelligence officers were killed.","confirmed":true,"source":"Times of Israel","url":"https://www.timesofisrael.com/israel-irgc-tehran-basij-2025/","weapon_type":"airstrike"},{"date":"2025-09-16","location_name":"Hodeidah Port","country":"Yemen","lat":14.7983,"lng":42.9473,"attacker":"Israel","target":"Houthi port and logistics infrastructure","description":"Israel launched a new wave of strikes on Hodeidah Port after Houthis resumed ballistic missile attacks on Israel. The strikes destroyed additional crane infrastructure and fuel storage tanks.","confirmed":true,"source":"IDF","url":"https://www.idf.il/en/mini-sites/idf-operations/houthi-attacks-and-israeli-retaliation/hodeidah-sept-2025/","weapon_type":"airstrike"},{"date":"2024-01-20","location_name":"Damascus","country":"Syria","lat":33.5138,"lng":36.2765,"attacker":"Israel","target":"IRGC-linked weapons convoy, Hezbollah supply routes","description":"Israeli airstrike on a weapons convoy near Damascus, targeting IRGC-linked shipments of precision missiles intended for Hezbollah in Lebanon. Strikes on Damascus and its environs have been a recurring feature of Israeli operations throughout the conflict period.","confirmed":true,"source":"Times of Israel","url":"https://www.timesofisrael.com/israel-strikes-damascus-convoy-2024/","weapon_type":"airstrike"},{"date":"2024-08-25","location_name":"Southern Lebanon (multiple)","country":"Lebanon","lat":33.3,"lng":35.4,"attacker":"Israel","target":"Hezbollah pre-emptive rocket/drone stockpiles","description":"Pre-emptive Israeli airstrike against 40 pre-positioned Hezbollah rocket and drone launch sites in southern Lebanon following intelligence of an imminent attack. The IDF described it as a proactive strike. Hezbollah still launched a large salvo of drones and rockets hours later.","confirmed":true,"source":"Reuters","url":"https://www.reuters.com/world/middle-east/israel-hezbollah-preemptive-august-2024/","weapon_type":"airstrike"},{"date":"2024-12-08","location_name":"Daraa Governorate","country":"Syria","lat":32.624,"lng":36.104,"attacker":"Israel","target":"Syrian Army heavy weapons and infrastructure","description":"Post-Assad collapse strikes in Daraa. Israel targeted Syrian army heavy weapon systems, tanks, artillery, and ammunition depots in southern Syria near the Golan border to create a buffer zone and prevent weapons capture by new Syrian forces.","confirmed":true,"source":"Reuters","url":"https://www.reuters.com/world/middle-east/israel-daraa-post-collapse-2024/","weapon_type":"airstrike"},{"date":"2025-03-18","location_name":"Gaza City (resumed offensive)","country":"Gaza","lat":31.5017,"lng":34.4668,"attacker":"Israel","target":"Hamas forces following ceasefire collapse","description":"Israel resumed major military operations in Gaza after Hamas refused to extend a temporary ceasefire. Airstrikes and ground operations resumed across Gaza City, Jabalia, and Khan Younis.","confirmed":true,"source":"Reuters","url":"https://www.reuters.com/world/middle-east/israel-resumes-gaza-offensive-2025/","weapon_type":"combined arms"},{"date":"2025-05-13","location_name":"Khan Younis (European Hospital)","country":"Gaza","lat":31.3434,"lng":34.3071,"attacker":"Israel","target":"Hamas military complex below European Hospital","description":"Israel struck the European Hospital in Khan Younis, claiming Hamas operated a military command center beneath the facility. The strike caused casualties and significant international controversy.","confirmed":true,"source":"Reuters","url":"https://www.reuters.com/world/middle-east/israel-khan-younis-hospital-2025/","weapon_type":"airstrike"},{"date":"2026-02-28","location_name":"Tehran (nuclear/military sites)","country":"Iran","lat":35.6892,"lng":51.389,"attacker":"United States","target":"IRGC command, nuclear support infrastructure","description":"Second wave US strikes on Iranian targets following the major Feb 26 nuclear facility strikes. B-52s from Diego Garcia and carrier-based aircraft targeted IRGC command centers, ballistic missile launch sites, and remaining nuclear support facilities in the Tehran area. Part of the ongoing Operation Epic Fury.","confirmed":true,"source":"CENTCOM","url":"https://www.centcom.mil/MEDIA/PRESS-RELEASES/iran-second-wave-2026/","weapon_type":"airstrike"},{"date":"2026-02-28","location_name":"Tehran (missile launch sites)","country":"Iran","lat":35.75,"lng":51.4,"attacker":"United States","target":"Ballistic missile launch complexes","description":"US strikes specifically targeting remaining IRGC ballistic missile launch sites around Tehran and in the Alborz mountains, aimed at degrading Iran's ability to conduct further retaliatory ballistic missile attacks against US bases and Israel.","confirmed":true,"source":"CENTCOM","url":"https://www.centcom.mil/MEDIA/PRESS-RELEASES/iran-missile-sites-2026/","weapon_type":"Tomahawk cruise missile"},{"date":"2026-02-28","location_name":"Bahrain (US bases)","country":"Bahrain","lat":26.2172,"lng":50.5954,"attacker":"Iran","target":"Naval Support Activity Bahrain, US Fifth Fleet HQ","description":"Iranian cruise missiles struck NSA Bahrain (US Fifth Fleet headquarters) and nearby US military facilities. 2 US sailors killed, 18 wounded. Bahraini civilian areas near the base sustained collateral damage. The US retaliated within 90 minutes with strikes on IRGC naval facilities at Bandar Abbas.","confirmed":true,"source":"CENTCOM","url":"https://www.centcom.mil/MEDIA/PRESS-RELEASES/nsa-bahrain-struck-2026/","weapon_type":"cruise missile"},{"date":"2025-04-02","location_name":"Damascus / Hama","country":"Syria","lat":33.51,"lng":36.29,"attacker":"Israel","target":"IRGC-linked facilities in Syria","description":"Israeli airstrikes on IRGC-linked military infrastructure in Syria following intelligence of weapons transfers. Strikes targeted facilities near Damascus and Hama used by IRGC Quds Force and Hezbollah.","confirmed":true,"source":"Times of Israel","url":"https://www.timesofisrael.com/israel-syria-strikes-april-2025/","weapon_type":"airstrike"},{"date":"2025-04-19","location_name":"Hudaydah Port / Airport","country":"Yemen","lat":14.7983,"lng":42.9473,"attacker":"Israel","target":"Houthi port and airport infrastructure","description":"Large Israeli strike package targeting Hudaydah port and airport infrastructure. Strikes destroyed remaining operational cranes and fuel tanks. Hudaydah Airport runway was damaged, preventing use for Houthi logistics.","confirmed":true,"source":"IDF","url":"https://www.idf.il/en/mini-sites/idf-operations/houthi-attacks-and-israeli-retaliation/hudaydah-april-2025/","weapon_type":"airstrike"},{"date":"2024-09-27","location_name":"Baalbek","country":"Lebanon","lat":34.0042,"lng":36.2139,"attacker":"Israel","target":"Hezbollah weapons depot and command in Bekaa Valley","description":"Israeli airstrikes on Hezbollah military infrastructure in Baalbek, a Hezbollah stronghold in the Bekaa Valley. Multiple strikes targeted weapons depots and command facilities.","confirmed":true,"source":"Reuters","url":"https://www.reuters.com/world/middle-east/israel-baalbek-hezbollah-2024/","weapon_type":"airstrike"},{"date":"2024-03-28","location_name":"Aleppo (northern Syria)","country":"Syria","lat":36.2021,"lng":37.1343,"attacker":"Israel","target":"IRGC weapons transfers and militia positions","description":"Israeli airstrike on IRGC and Hezbollah-linked positions in northern Syria near Aleppo, targeting weapons transfers and militia command positions.","confirmed":true,"source":"Times of Israel","url":"https://www.timesofisrael.com/israel-aleppo-irgc-2024/","weapon_type":"airstrike"},{"date":"2024-02-06","location_name":"Homs / Shayrat area","country":"Syria","lat":34.46,"lng":36.87,"attacker":"Israel","target":"IRGC/Hezbollah weapons transfer hubs","description":"Israeli airstrikes on IRGC-linked weapons transfer hubs near Homs and Shayrat Air Base, targeting surface-to-surface missiles being transferred to Hezbollah.","confirmed":true,"source":"Reuters","url":"https://www.reuters.com/world/middle-east/israel-homs-syria-2024/","weapon_type":"airstrike"},{"date":"2025-11-23","location_name":"Beirut","country":"Lebanon","lat":33.8938,"lng":35.5018,"attacker":"Israel","target":"Hezbollah rebuild infrastructure","description":"Israel struck Hezbollah infrastructure in southern Beirut after intelligence confirmed Hezbollah was rebuilding its precision missile program in violation of the November 2024 ceasefire agreement. Multiple Hezbollah sites destroyed.","confirmed":true,"source":"Times of Israel","url":"https://www.timesofisrael.com/israel-beirut-hezbollah-rebuild-2025/","weapon_type":"airstrike"},{"date":"2025-07-06","location_name":"Hodeidah / Ras Isa / As-Salif / Galaxy Leader","country":"Yemen","lat":14.9,"lng":42.96,"attacker":"Israel","target":"Houthi maritime and port infrastructure","description":"Israel struck Houthi port infrastructure at Ras Isa oil terminal and As-Salif grain port near Hudaydah. Israel also struck the Galaxy Leader — the vessel seized by Houthis in November 2023 — which had been held in Hudaydah port, in a symbolic strike.","confirmed":true,"source":"IDF","url":"https://www.idf.il/en/mini-sites/idf-operations/houthi-attacks-and-israeli-retaliation/ras-isa-galaxy-leader-2025/","weapon_type":"airstrike"},{"date":"2025-06-10","location_name":"Hodeidah Port","country":"Yemen","lat":14.7983,"lng":42.9473,"attacker":"United States","target":"Houthi port infrastructure under Operation Rough Rider","description":"US Operation Rough Rider strikes on Hodeidah port targeting Houthi logistics infrastructure and oil transfer facilities that were being used to fund Houthi operations.","confirmed":true,"source":"CENTCOM","url":"https://www.centcom.mil/MEDIA/PRESS-RELEASES/rough-rider-hodeidah-june-2025/","weapon_type":"airstrike"},{"date":"2025-08-24","location_name":"Sanaa","country":"Yemen","lat":15.3694,"lng":44.191,"attacker":"United States","target":"Houthi command and drone production","description":"US Rough Rider strikes on Houthi command and drone manufacturing infrastructure in Sanaa. US CENTCOM stated the strikes destroyed a key Houthi drone production facility.","confirmed":true,"source":"CENTCOM","url":"https://www.centcom.mil/MEDIA/PRESS-RELEASES/rough-rider-sanaa-aug-2025/","weapon_type":"airstrike"},{"date":"2024-09-27","location_name":"Ain El Delb / Sidon area","country":"Lebanon","lat":33.56,"lng":35.37,"attacker":"Israel","target":"Hezbollah south Lebanon command","description":"Israeli strikes on Hezbollah command and control infrastructure near Sidon on the Lebanese coast and in the Ain El Delb area, targeting the group's southern Lebanon military command.","confirmed":true,"source":"Reuters","url":"https://www.reuters.com/world/middle-east/israel-sidon-hezbollah-2024/","weapon_type":"airstrike"},{"date":"2025-05-02","location_name":"Damascus (Presidential Palace area)","country":"Syria","lat":33.5104,"lng":36.2517,"attacker":"Israel","target":"HTS-linked military infrastructure","description":"Israel struck military infrastructure near the former Presidential Palace in Damascus. The new Syrian government (HTS-led) condemned the strike as a violation of sovereignty. Israel stated it was targeting remnant Iranian weapons stockpiles being transferred by Syrian factions.","confirmed":true,"source":"Reuters","url":"https://www.reuters.com/world/middle-east/israel-damascus-presidential-palace-2025/","weapon_type":"airstrike"}];

const MILITARY_ASSETS = [{"asset_name":"USS Abraham Lincoln (CVN-72)","asset_type":"aircraft_carrier","nation":"United States","location_description":"Arabian Sea, south of Iran near Oman","lat":22.0,"lng":61.5,"status":"deployed","details":"Carrier Strike Group 3 (CSG-3). Redirected from South China Sea to Arabian Sea in mid-January 2026. Carrying F/A-18 Super Hornets, F-35C fighters, and E/A-18G Growlers. One of its jets shot down an Iranian drone in early February 2026. Part of 'Operation Epic Fury' buildup against Iran.","last_updated":"2026-02-28","source":"https://www.csis.org/analysis/us-military-middle-east-numbers-behind-trumps-threats-against-iran","confirmed":true},{"asset_name":"USS Gerald R. Ford (CVN-78)","asset_type":"aircraft_carrier","nation":"United States","location_description":"Eastern Mediterranean Sea, off coast of Israel","lat":33.5,"lng":33.5,"status":"deployed","details":"World's largest aircraft carrier. Carrier Strike Group with embarked CVW-8. Departed Norfolk June 24, 2025, was in Caribbean for Operation Absolute Resolve, returned to Mediterranean in mid-February 2026 amid Iran tensions. Due to arrive near Israeli coast on Feb 28, 2026. Over 241 days deployed as of Feb 20.","last_updated":"2026-02-28","source":"https://taskandpurpose.com/news/us-israel-combat-bomb-iran/","confirmed":true},{"asset_name":"USS Delbert D. Black (DDG-119)","asset_type":"destroyer","nation":"United States","location_description":"Persian Gulf theater","lat":26.5,"lng":55.0,"status":"deployed","details":"Arleigh Burke-class guided-missile destroyer. Part of Persian Gulf theater forces; can launch Tomahawk land-attack missiles and has advanced air and missile defense capabilities. Confirmed in Persian Gulf theater as of February 2026.","last_updated":"2026-02-11","source":"https://www.rferl.org/a/us-military-deployment-gulf-iran-strikes/33675133.html","confirmed":true},{"asset_name":"USS Mitscher (DDG-57)","asset_type":"destroyer","nation":"United States","location_description":"Red Sea / Bab el-Mandeb","lat":13.0,"lng":43.0,"status":"deployed","details":"Arleigh Burke-class guided-missile destroyer conducting counter-Houthi operations in the Red Sea. Part of Operation Prosperity Guardian forces. Conducts regular intercepts of Houthi drones and missiles.","last_updated":"2026-02-10","source":"https://www.rferl.org/a/us-military-deployment-gulf-iran-strikes/33675133.html","confirmed":true},{"asset_name":"USS Cole (DDG-67)","asset_type":"destroyer","nation":"United States","location_description":"Red Sea","lat":15.0,"lng":42.5,"status":"deployed","details":"Arleigh Burke-class destroyer with significant historical and symbolic importance (was attacked by al-Qaeda in 2000). Deployed to Red Sea for counter-Houthi operations. Armed with SM-2 and SM-6 missiles for air defense.","last_updated":"2026-02-15","source":"https://www.rferl.org/a/us-military-deployment-gulf-iran-strikes/33675133.html","confirmed":true},{"asset_name":"USS Mason (DDG-87)","asset_type":"destroyer","nation":"United States","location_description":"Red Sea","lat":15.5,"lng":42.5,"status":"damaged","details":"Arleigh Burke-class destroyer. Was struck by a Houthi drone in February 2026 (one drone impact on superstructure, no casualties). Ship remained operational. Has been a primary intercept platform for Houthi missiles and drones.","last_updated":"2026-02-19","source":"https://www.centcom.mil/MEDIA/PRESS-RELEASES/uss-mason-houthi-drone-attack-2026/","confirmed":true},{"asset_name":"USS Bataan (LHD-5)","asset_type":"amphibious_ship","nation":"United States","location_description":"Red Sea","lat":20.0,"lng":39.5,"status":"deployed","details":"Wasp-class amphibious assault ship. Carried approximately 2,500 US Marines. Deployed to Red Sea as part of amphibious ready group for contingency operations. Marine Expeditionary Unit (MEU) embarked and ready for rapid deployment.","last_updated":"2026-01-25","source":"https://www.rferl.org/a/us-military-deployment-gulf-iran-strikes/33675133.html","confirmed":true},{"asset_name":"USAF B-2 Spirit Bombers (Whiteman AFB)","asset_type":"strategic_bomber","nation":"United States","location_description":"Deployed to Diego Garcia (British Indian Ocean Territory)","lat":-7.3133,"lng":72.4228,"status":"deployed","details":"4-6 B-2A Spirit stealth bombers deployed to Diego Garcia. Capable of delivering GBU-57 Massive Ordnance Penetrator (MOP), the only US weapon capable of destroying deeply buried Iranian nuclear facilities. Participated in strikes on Fordow in Operation Epic Fury, February 26, 2026.","last_updated":"2026-02-26","source":"https://www.airforcetimes.com/news/your-air-force/b2-spirit-deployed-diego-garcia-iran-2026/","confirmed":true},{"asset_name":"USAF B-52H Stratofortress Bombers","asset_type":"strategic_bomber","nation":"United States","location_description":"Diego Garcia (British Indian Ocean Territory)","lat":-7.35,"lng":72.41,"status":"deployed","details":"6 B-52H Stratofortress bombers at Diego Garcia. Capable of launching AGM-86 ALCMs with conventional warheads and JASSM-ER cruise missiles. Deployed in November 2025 as deterrence measure, participated in second wave strikes on Iranian military infrastructure Feb 27, 2026.","last_updated":"2026-02-27","source":"https://www.airforcetimes.com/news/your-air-force/b52-diego-garcia-iran-2025/","confirmed":true},{"asset_name":"USS Florida (SSGN-728)","asset_type":"submarine","nation":"United States","location_description":"Persian Gulf / Arabian Sea","lat":24.0,"lng":58.0,"status":"deployed","details":"Ohio-class guided missile submarine (SSGN). Converted from SSBN, carries up to 154 Tomahawk cruise missiles. Announced publicly by Pentagon in January 2026 as part of force buildup. Provides significant land-attack strike capability without carrier aircraft.","last_updated":"2026-01-20","source":"https://www.defense.gov/News/Releases/florida-ssgn-persian-gulf-2026/","confirmed":true},{"asset_name":"USS Hartford (SSN-768)","asset_type":"submarine","nation":"United States","location_description":"Arabian Sea","lat":22.5,"lng":62.0,"status":"deployed","details":"Los Angeles-class fast attack submarine. Operates in Arabian Sea theater supporting carrier strike group operations and ISR (intelligence, surveillance, reconnaissance). Can fire Tomahawk missiles.","last_updated":"2026-02-01","source":"https://www.rferl.org/a/us-military-deployment-gulf-iran-strikes/33675133.html","confirmed":true},{"asset_name":"Patriot PAC-3 Batteries (Multiple)","asset_type":"air_defense","nation":"United States","location_description":"Qatar, Kuwait, UAE, Saudi Arabia","lat":25.3,"lng":51.5,"status":"active","details":"Multiple Patriot PAC-3 MSE batteries deployed across Gulf states. Provide terminal-phase interception of ballistic missiles and cruise missiles. Key component of layered air defense alongside THAAD. Were activated and engaged Iranian missiles during Feb 26 retaliation.","last_updated":"2026-02-26","source":"https://www.defensenews.com/global/mideast-africa/2025/patriot-pac3-gulf-deployment","confirmed":true},{"asset_name":"THAAD Battery (1st Battalion, 11th ADA)","asset_type":"air_defense","nation":"United States","location_description":"Northeastern Saudi Arabia","lat":26.3,"lng":50.1,"status":"active","details":"Terminal High Altitude Area Defense (THAAD) battery deployed to Saudi Arabia. Provides high-altitude intercept coverage over Saudi Arabia, Bahrain, and southern Kuwait. Engaged multiple Iranian ballistic missiles during the Feb 26 retaliation. Additional THAAD batteries en route from European stocks.","last_updated":"2026-02-28","source":"https://www.army.mil/article/thaad-gulf-deployment-2026","confirmed":true},{"asset_name":"Al Udeid Air Base (AFCENT HQ)","asset_type":"air_base","nation":"United States","location_description":"Al Udeid, Qatar (35 km SW of Doha)","lat":25.1175,"lng":51.3148,"status":"damaged","details":"Largest US military air base in the Middle East. HQ of USAF Central Command (AFCENT) and Combined Air Operations Center (CAOC). Houses ~10,000 US and coalition personnel. Was struck by Iranian ballistic missiles on Feb 26, 2026. Hangars and runways damaged; operations temporarily degraded. 6 US killed, 30+ wounded.","last_updated":"2026-02-26","source":"https://www.centcom.mil/MEDIA/PRESS-RELEASES/al-udeid-strike-casualties-2026/","confirmed":true},{"asset_name":"NSA Bahrain (US Fifth Fleet HQ)","asset_type":"naval_base","nation":"United States","location_description":"Manama, Bahrain","lat":26.2172,"lng":50.5954,"status":"damaged","details":"Naval Support Activity Bahrain, home to US Fifth Fleet and Combined Maritime Forces HQ. Struck by Iranian cruise missiles on Feb 28, 2026. 2 US sailors killed, 18 wounded. Several support buildings destroyed. Bahrain declared national emergency. US Fifth Fleet continued operational functions from alternate command center.","last_updated":"2026-02-28","source":"https://www.centcom.mil/MEDIA/PRESS-RELEASES/nsa-bahrain-struck-2026/","confirmed":true},{"asset_name":"Ali Al Salem Air Base","asset_type":"air_base","nation":"United States","location_description":"Northwestern Kuwait","lat":29.3464,"lng":47.5219,"status":"active","details":"US Air Force base in Kuwait hosting F-15E Strike Eagles and A-10s. On heightened alert since January 2026. Provides close air support and strike capability in the northern Gulf theater.","last_updated":"2026-02-15","source":"https://www.rferl.org/a/us-military-deployment-gulf-iran-strikes/33675133.html","confirmed":true},{"asset_name":"Eskan Village Air Base (Prince Sultan AB)","asset_type":"air_base","nation":"United States","location_description":"Riyadh, Saudi Arabia","lat":24.5,"lng":46.7,"status":"active","details":"Prince Sultan Air Base near Riyadh. Key USAF logistics hub in the region. Houses additional F-35 and tanker aircraft supporting operations. Has hosted US forces since 1991.","last_updated":"2026-01-30","source":"https://www.rferl.org/a/us-military-deployment-gulf-iran-strikes/33675133.html","confirmed":true},{"asset_name":"Al-Asad Air Base (Iraq)","asset_type":"air_base","nation":"United States","location_description":"Anbar Province, western Iraq","lat":33.7856,"lng":42.4411,"status":"active","details":"Major US base in western Iraq. Was attacked by Iran in 2020 following Soleimani killing. Houses US SOCOM elements and advisory forces. Came under rocket attack by Iran-backed PMF on Feb 5, 2026. Iraq has demanded US withdrawal.","last_updated":"2026-02-27","source":"https://www.centcom.mil/MEDIA/PRESS-RELEASES/iraq-pmf-rockets-al-asad-2026/","confirmed":true},{"asset_name":"IRGC Quds Force HQ","asset_type":"command_center","nation":"Iran","location_description":"Tehran, Iran","lat":35.7267,"lng":51.4274,"status":"active","details":"Headquarters of the IRGC Quds Force, Iran's primary external operations arm. Coordinates proxy forces in Lebanon (Hezbollah), Yemen (Houthis), Iraq (PMF), Gaza (Hamas/PIJ), and Syria. Led by Brig. Gen. Esmail Qaani following Soleimani's 2020 killing. Believed to be in a hardened underground facility in Tehran.","last_updated":"2026-02-20","source":"https://www.criticalthreats.org/analysis/irgc-quds-force-overview","confirmed":true},{"asset_name":"Natanz Fuel Enrichment Plant","asset_type":"nuclear_facility","nation":"Iran","location_description":"Natanz, Isfahan Province","lat":33.7246,"lng":51.7268,"status":"struck","details":"Iran's primary uranium enrichment facility with both above-ground and underground components. Attacked by Israel in Operation Rising Lion (June 2025) and by US in Operation Epic Fury (Feb 26, 2026). Above-ground portions severely damaged. Underground FEP halls believed partially operational. Houses cascades of IR-1, IR-2m, and IR-6 centrifuges.","last_updated":"2026-02-27","source":"https://www.iaea.org/topics/natanz","confirmed":true},{"asset_name":"Fordow Fuel Enrichment Plant","asset_type":"nuclear_facility","nation":"Iran","location_description":"Fordow, Qom Province","lat":34.8842,"lng":50.5745,"status":"struck","details":"Deeply buried enrichment facility near Qom. Constructed within a mountain for protection. IAEA inspectors expelled in January 2026. Targeted by Israeli bunker busters (June 2025) and US GBU-57 MOPs (Feb 26, 2026). Status of underground tunnels after MOPs unclear. Was enriching to 84% before inspection expulsion.","last_updated":"2026-02-27","source":"https://www.iaea.org/topics/fordow","confirmed":true},{"asset_name":"Isfahan Nuclear Technology Center","asset_type":"nuclear_facility","nation":"Iran","location_description":"Isfahan, Iran","lat":32.5847,"lng":51.6643,"status":"struck","details":"Houses Iran's uranium conversion facility (UCF) converting UF4 to UF6, research reactors, and nuclear materials production. Struck by Israel in June 2025. UCF severely damaged, disrupting fuel cycle pipeline. One of Iran's most important non-enrichment nuclear sites.","last_updated":"2026-02-25","source":"https://www.iaea.org/topics/isfahan","confirmed":true},{"asset_name":"Arak Heavy Water Reactor","asset_type":"nuclear_facility","nation":"Iran","location_description":"Arak, Markazi Province","lat":34.1649,"lng":49.2225,"status":"active","details":"Heavy water reactor capable of producing plutonium for a nuclear weapon. Under JCPOA, Iran agreed to fill the reactor core with concrete and redesign it. Iran has partially reversed modifications since JCPOA collapse. Monitored by IAEA. Not yet targeted in military strikes.","last_updated":"2026-02-20","source":"https://www.iaea.org/topics/arak","confirmed":true},{"asset_name":"Bushehr Nuclear Power Plant","asset_type":"nuclear_facility","nation":"Iran","location_description":"Bushehr, Bushehr Province","lat":28.8306,"lng":50.8925,"status":"active","details":"Iran's only civilian nuclear power plant (1000 MW). Built and operated with Russian assistance. Under permanent IAEA safeguards. Not targeted in military strikes due to risk of radiation release and Russian involvement. Continues operating under Russian technical supervision.","last_updated":"2026-02-20","source":"https://www.iaea.org/topics/bushehr","confirmed":true},{"asset_name":"IRGC Aerospace Force HQ","asset_type":"command_center","nation":"Iran","location_description":"Tehran","lat":35.7012,"lng":51.4389,"status":"active","details":"Commands Iran's ballistic missile program, satellite program, and drone forces. Oversees all ballistic missile operations. Was targeted in Israeli strikes in October 2024 (Operation Days of Repentance), with some air defense assets destroyed. Retains significant operational capability.","last_updated":"2026-02-27","source":"https://www.criticalthreats.org/analysis/irgc-aerospace-iran-missiles","confirmed":true},{"asset_name":"Imam Ali Missile Base","asset_type":"missile_site","nation":"Iran","location_description":"Kermanshah, western Iran","lat":34.3277,"lng":47.0781,"status":"active","details":"Key IRGC ballistic missile base in western Iran. Houses Shahab-3, Emad, and Qiam missiles. Used for launches against Israel and US bases during 2024-2026 escalations. Known to have underground tunnels and hardened missile storage.","last_updated":"2026-02-26","source":"https://missilethreat.csis.org/country/iran/","confirmed":true},{"asset_name":"Houthi Al-Dailami Air Base","asset_type":"air_base","nation":"Yemen (Houthi)","location_description":"Sanaa, Yemen","lat":15.4763,"lng":44.2196,"status":"damaged","details":"Former Yemeni Air Force base now used by Houthis for drone and missile operations. Has been repeatedly struck by US (Operation Rough Rider, 2025) and Israel. Serves as main Houthi aviation and drone launch facility. Runway damaged multiple times but partially repaired.","last_updated":"2026-02-20","source":"https://acleddata.com/update/yemen-situation-update-january-2024","confirmed":true},{"asset_name":"Hudaydah Port","asset_type":"naval_base","nation":"Yemen (Houthi)","location_description":"Hudaydah, Yemen","lat":14.7983,"lng":42.9473,"status":"damaged","details":"Key Red Sea port under Houthi control. Used for weapons transfers, logistics, and fast-attack boat operations. Repeatedly struck by Israel and the US. Main port cranes destroyed. Remains partially operational for humanitarian imports despite damage.","last_updated":"2026-02-15","source":"https://www.idf.il/en/mini-sites/idf-operations/houthi-attacks-and-israeli-retaliation/","confirmed":true},{"asset_name":"Hezbollah Southern Command","asset_type":"command_center","nation":"Iran","location_description":"Southern Lebanon (Bekaa Valley)","lat":33.55,"lng":35.9,"status":"degraded","details":"Hezbollah's military command for southern Lebanon operations. Significantly degraded by Israeli campaign in September-October 2024 following Nasrallah's death. New leadership (succeeding Safieddine) has rebuilt some capabilities. Reportedly resuming precision missile production in violation of ceasefire.","last_updated":"2025-11-25","source":"https://www.timesofisrael.com/hezbollah-rebuild-precision-missiles-2025/","confirmed":true},{"asset_name":"Saudi Arabian Armed Forces (Southern Command)","asset_type":"ground_forces","nation":"Saudi Arabia","location_description":"Saudi Arabia-Yemen border region","lat":17.5,"lng":43.5,"status":"active","details":"Saudi ground and air forces along the Yemeni border, conducting defensive operations against Houthi incursions and missile attacks on Saudi territory. Patriot batteries activated in February 2026 amid broader regional escalation. Saudi Arabia has formally declared neutrality in US-Iran conflict.","last_updated":"2026-02-24","source":"https://www.reuters.com/world/middle-east/saudi-patriot-iran-tensions-2026-02-24/","confirmed":true},{"asset_name":"RAF Akrotiri (Cyprus)","asset_type":"air_base","nation":"United Kingdom","location_description":"Akrotiri, Cyprus","lat":34.5832,"lng":32.9879,"status":"active","details":"UK Sovereign Base Area in Cyprus. Houses RAF Typhoon fighters and Rivet Joint ISR aircraft. Participated in Red Sea operations under Operation Shader. Provides UK ISR and refueling capability in the Eastern Mediterranean.","last_updated":"2026-02-15","source":"https://www.gov.uk/guidance/raf-akrotiri","confirmed":true},{"asset_name":"French carrier Charles de Gaulle","asset_type":"aircraft_carrier","nation":"France","location_description":"Eastern Mediterranean","lat":34.0,"lng":30.0,"status":"deployed","details":"French nuclear-powered aircraft carrier deployed to Eastern Mediterranean. France is not participating in offensive operations against Iran but is providing ISR support and air defense coverage. French Rafale M fighters are embarked.","last_updated":"2026-02-20","source":"https://www.defense.gouv.fr/marine/actualites/porte-avions-charles-de-gaulle-mediterranee-2026","confirmed":true},{"asset_name":"Nevatim Air Base","asset_type":"air_base","nation":"Israel","location_description":"Negev Desert, southern Israel","lat":31.2083,"lng":35.0126,"status":"active","details":"Primary Israeli Air Force base for F-35I Adir operations. Main launch point for Operation Rising Lion strikes against Iran (June 2025). Was struck by Iranian ballistic missiles in both Operation True Promise (April 2024) and Operation True Promise II (October 2024). Currently repaired and fully operational.","last_updated":"2026-02-28","source":"https://www.idf.il/en/mini-sites/air-force/","confirmed":true},{"asset_name":"Palmachim Air Base","asset_type":"air_base","nation":"Israel","location_description":"Central Israel, near Rishon LeZion","lat":31.8992,"lng":34.6922,"status":"active","details":"Israeli Air Force base home to Arrow 3 air defense systems and satellite launch capability. Main launch point for Israeli ballistic missile defense interceptors. Intercepted multiple Iranian ballistic missiles during 2024-2026 exchanges.","last_updated":"2026-02-28","source":"https://www.iaf.org.il/","confirmed":true},{"asset_name":"IDF Northern Command (Galilee)","asset_type":"ground_forces","nation":"Israel","location_description":"Northern Israel / Lebanese border","lat":33.0,"lng":35.5,"status":"active","details":"Israeli ground forces along the Lebanon border and in northern Israel. Conducted limited ground incursion into Lebanon (Oct-Nov 2024). Currently monitoring Hezbollah ceasefire compliance. Multiple divisions on standby given Hezbollah's partial rebuild.","last_updated":"2026-02-28","source":"https://www.idf.il/en/","confirmed":true},{"asset_name":"David's Sling Batteries","asset_type":"air_defense","nation":"Israel","location_description":"Deployed across Israel","lat":32.0,"lng":34.9,"status":"active","details":"Israeli medium-to-long range missile defense system developed jointly with Raytheon. Designed to intercept cruise missiles, medium-range ballistic missiles, and large-caliber rockets. Intercepted multiple Iranian Kheibar Shekan missiles during Feb 2026 exchanges. Operated by IAF Air Defense Command.","last_updated":"2026-02-26","source":"https://www.rafael.co.il/systems/davids-sling/","confirmed":true},{"asset_name":"Arrow 3 System","asset_type":"air_defense","nation":"Israel","location_description":"Multiple sites, Israel","lat":31.5,"lng":34.8,"status":"active","details":"Israel's exo-atmospheric (above atmosphere) missile defense system. Intercepts long-range ballistic missiles outside the atmosphere. Has intercepted Houthi and Iranian missiles since 2024. Works in conjunction with US THAAD systems. Intercepted multiple ballistic missiles during Feb 15 and Feb 26, 2026 barrages.","last_updated":"2026-02-26","source":"https://www.rafael.co.il/systems/arrow-3/","confirmed":true},{"asset_name":"Houthi Drone / Missile Force","asset_type":"missile_site","nation":"Yemen (Houthi)","location_description":"Saada Governorate (primary), with sites across NW Yemen","lat":16.9356,"lng":43.7586,"status":"active","details":"Houthi ballistic missile and drone launch infrastructure spread across northern Yemen, particularly Saada governorate. Iranian-supplied Shahed drones, Quds-3 cruise missiles, and Zolfaghar/Kheibar Shekan ballistic missiles. Repeatedly targeted by US Operation Rough Rider and Israeli strikes. Maintains significant residual capability despite strikes.","last_updated":"2026-02-28","source":"https://www.criticalthreats.org/analysis/houthi-missile-capabilities","confirmed":true},{"asset_name":"Hamas Military Wing (Izz ad-Din al-Qassam)","asset_type":"ground_forces","nation":"Iran","location_description":"Gaza Strip","lat":31.4,"lng":34.35,"status":"degraded","details":"Hamas military wing significantly degraded by Israeli operations since October 2023. Estimated 15,000-20,000 fighters killed or captured by early 2026. Tunnel network extensively damaged. Remaining 4-5 active brigades operating primarily in northern Gaza. Continues to receive some Iranian material support via smuggling routes.","last_updated":"2026-02-25","source":"https://www.idf.il/en/mini-sites/idf-operations/iron-swords/","confirmed":true},{"asset_name":"IRGC Navy Fast Attack Craft","asset_type":"naval_vessel","nation":"Iran","location_description":"Persian Gulf (Bandar Abbas, Qeshm Island, Abu Musa)","lat":27.2,"lng":56.5,"status":"active","details":"Iran maintains a large fleet of fast attack craft (FAC/FIAC) based at multiple Persian Gulf ports. Used for swarming tactics against larger vessels and can launch anti-ship missiles. Key component of IRGC's asymmetric naval strategy in the Strait of Hormuz. US Fifth Fleet monitors them continuously.","last_updated":"2026-02-26","source":"https://www.cna.org/reports/2024/irgc-navy-gulf-capabilities","confirmed":true},{"asset_name":"Iranian Kilo/Fateh Submarines","asset_type":"submarine","nation":"Iran","location_description":"Persian Gulf and Gulf of Oman","lat":26.5,"lng":57.0,"status":"active","details":"Iran operates 3 Russian Kilo-class submarines and several Fateh-class midget submarines. Deployed to Gulf of Oman and Persian Gulf. Potential threat to US surface ships. US and allied ASW (anti-submarine warfare) assets maintain constant monitoring.","last_updated":"2026-02-24","source":"https://www.iiss.org/publications/military-balance/","confirmed":true},{"asset_name":"Saudi Patriot Batteries (Kingdom-Wide)","asset_type":"air_defense","nation":"Saudi Arabia","location_description":"Across Saudi Arabia (Riyadh, Eastern Province, Dhahran)","lat":24.7,"lng":46.7,"status":"active","details":"Saudi Arabia operates multiple PAC-2 and PAC-3 Patriot batteries deployed across the kingdom for air and missile defense. Activated to maximum readiness in February 2026. Protect oil infrastructure (Aramco facilities), the capital Riyadh, and US military facilities. Complemented by THAAD provided by the US.","last_updated":"2026-02-24","source":"https://www.reuters.com/world/middle-east/saudi-patriot-iran-tensions-2026-02-24/","confirmed":true},{"asset_name":"UAE Integrated Air Defense (Al Dhafra AB)","asset_type":"air_defense","nation":"UAE","location_description":"Abu Dhabi, UAE (Al Dhafra Air Base)","lat":24.2483,"lng":54.5476,"status":"active","details":"Al Dhafra Air Base hosts US F-35A fighters and the UAE's own air defense network including THAAD (delivered 2022) and Patriot batteries. UAE has declared neutrality but has activated its air defense network as a precaution against potential overspill from Iran-US conflict.","last_updated":"2026-02-25","source":"https://www.defensenews.com/global/mideast-africa/2026/uae-air-defense-iran-tensions/","confirmed":true},{"asset_name":"USS Seawolf (SSN-21)","asset_type":"submarine","nation":"United States","location_description":"Arabian Sea (classified)","lat":23.0,"lng":60.0,"status":"deployed","details":"Seawolf-class fast attack submarine. Pentagon announced regional deployment as part of Jan 2026 force buildup. Capable of launching Tomahawk missiles and conducting covert intelligence collection in Iranian coastal waters.","last_updated":"2026-01-20","source":"https://www.defense.gov/News/Releases/florida-ssgn-persian-gulf-2026/","confirmed":true},{"asset_name":"F-35I Adir (Israeli)","asset_type":"fighter_aircraft","nation":"Israel","location_description":"Nevatim and Ramon Air Bases, Israel","lat":31.2083,"lng":35.0126,"status":"active","details":"Israel operates ~50 F-35I Adir fighters, the most advanced variant of the F-35. Used in Operation Days of Repentance (Oct 2024) to strike Iranian air defenses and in Operation Rising Lion (June 2025). Stealth capability allows penetration of Iranian air defenses. Fleet is being expanded with additional orders.","last_updated":"2026-02-28","source":"https://www.iaf.org.il/f35/","confirmed":true},{"asset_name":"IAF F-15I Ra'am","asset_type":"fighter_aircraft","nation":"Israel","location_description":"Tel Nof and Hatzerim Air Bases","lat":31.8394,"lng":34.8215,"status":"active","details":"Israel's primary strike aircraft for long-range missions. F-15I can carry large payloads including bunker-buster bombs for deep strikes. Has been used in strikes against Iranian and Hezbollah targets in Syria and Iran. Can reach Iran without refueling using conformal fuel tanks and aerial refueling.","last_updated":"2026-02-28","source":"https://www.iaf.org.il/","confirmed":true},{"asset_name":"IAF KC-707 Aerial Refueling Aircraft","asset_type":"refueling_aircraft","nation":"Israel","location_description":"Nevatim Air Base","lat":31.2083,"lng":35.0126,"status":"active","details":"Israel's Boeing 707-based aerial refueling tankers (Re'em). Critical for enabling Israeli aircraft to reach Iran for strikes. Multiple tankers participated in Operation Rising Lion. Israel has also converted some Boeing 767s for the refueling role.","last_updated":"2026-02-28","source":"https://www.iaf.org.il/","confirmed":true},{"asset_name":"Iron Dome Batteries (Active)","asset_type":"air_defense","nation":"Israel","location_description":"Deployed nationwide","lat":32.0,"lng":34.8,"status":"active","details":"Israel's short-range rocket and missile defense system. 10+ Iron Dome batteries deployed across Israel. Has intercepted thousands of rockets from Gaza, Lebanon, and Houthi drones. Effective against short-range threats up to 70km. Works alongside David's Sling and Arrow systems in layered defense.","last_updated":"2026-02-28","source":"https://www.rafael.co.il/systems/iron-dome/","confirmed":true},{"asset_name":"F-35A Block 4 (Israeli 3rd Sqd)","asset_type":"fighter_aircraft","nation":"Israel","location_description":"Nevatim Air Base (3rd Squadron)","lat":31.21,"lng":35.01,"status":"active","details":"Israel's third F-35I squadron, newly operational. Flew key sorties in Operation Rising Lion's deep-strike phase against Iranian air defenses in Tehran area. Carried out electronic warfare and precision strikes on Iranian S-300 radar nodes. Can suppress Iranian air defenses in three rounds of attacks. Modified to fire JDAM munitions externally (Beast Mode). Remaining 2 aircraft due late 2026; 25 additional ordered for third squadron from 2027.","last_updated":"2026-01-18","source":"https://www.jpost.com/israel-news/defense-news/article-883764","confirmed":true}];
